#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const double pi=acos(-1);const int N=3e6+10;
struct cpx
{
	double a,b;inline cpx(double A=0,double B=0){a=A;b=B;}
	inline cpx operator + (const cpx &x)const{return cpx(a+x.a,b+x.b);}
	inline cpx operator - (const cpx &x)const{return cpx(a-x.a,b-x.b);}
	inline cpx operator * (const cpx &x)const{return cpx(a*x.a-b*x.b,a*x.b+b*x.a);} 
}f[N],g[N],tmp[N];char s[N];int n,m,p;int ans[N];
inline void fft(cpx *f,int len,bool flag)
{
	if(len==1)return;cpx *fl=f,*fr=f+len/2;
	rep(0,len-1,i)tmp[i]=f[i];rep(0,len/2-1,i)fl[i]=tmp[i<<1],fr[i]=tmp[i<<1|1];
	fft(fl,len/2,flag);fft(fr,len/2,flag);
	cpx Rt(cos(2*pi/len),(flag?1:-1)*sin(2*pi/len)),cur(1,0);
	rep(0,len/2-1,i){cpx q=cur*fr[i];tmp[i]=fl[i]+q;tmp[i+len/2]=fl[i]-q;cur=cur*Rt;}
	rep(0,len-1,i)f[i]=tmp[i];return;
}
int main()
{
	scanf("%s",s);n=strlen(s);--n;p=n;rep(0,n,i)f[i]=cpx(s[p--]-'0',0);
	scanf("%s",s);m=strlen(s);--m;p=m;rep(0,m,i)g[i]=cpx(s[p--]-'0',0);
//	rep(0,n,i)printf("%.0lf ",f[i].a);rep(0,m,i)printf("%.0lf ",g[i].a);
	m+=n;n=1;while(n<=m)n=n<<1;fft(f,n,1);fft(g,n,1);rep(0,n-1,i)f[i]=f[i]*g[i];fft(f,n,0);
	rep(0,n,i)
	{
		ans[i]+=int(round(f[i].a/n));
		if(ans[i]>9)ans[i+1]+=ans[i]/10,ans[i]%=10,n+=(i==n);
	}
    while(!ans[n]&&n)n--;++n;while((--n)>=0)printf("%d",ans[n]);
}
